//! Spec-compliance tests: Paragraph Spacing & Indentation Audit
//!
//! These tests verify behavioral constraints from ECMA-376 §17.3.1.33
//! (spacing) and §17.3.1.12 (ind).
//!
//! Each test cites the specific spec section and constraint it verifies.
//!
//! Fixture DOCX files are generated by
//! `testdata/spec-compliance/spacing-audit/create_docs.py`.

use stemma::LineSpacingRule;

use crate::common;

const FIXTURES: &str = "testdata/spec-compliance/spacing-audit";

// =========================================================================
// SA-01: beforeAutospacing / afterAutospacing override before/after
// =========================================================================
//
// §17.3.1.33: "If [beforeAutospacing] is specified, then any value in
// before or beforeLines is ignored, and the spacing is automatically
// determined by the consumer."
//
// The autospacing flags are parsed, stored in the domain model, and
// serialized. Raw before/after/beforeLines/afterLines values are
// preserved for roundtrip fidelity, but the autospacing flag tells
// consumers to ignore them.

/// §17.3.1.33: beforeAutospacing="1" — flag is parsed, raw value preserved.
#[test]
fn sa01_autospacing_before_flag_and_value() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "autospacing-override");
    let paras = common::all_paragraphs(&doc);
    assert!(
        paras.len() >= 4,
        "expected at least 4 paragraphs, got {}",
        paras.len()
    );

    // P2 is the control with no autospacing — before=480 is valid there.
    let sp2 = paras[2]
        .spacing
        .as_ref()
        .expect("P2 (control) should have spacing");
    assert_eq!(sp2.before, Some(480), "P2 (control) before should be 480");
    assert_eq!(sp2.after, Some(480), "P2 (control) after should be 480");
    assert!(
        sp2.before_autospacing.is_none() || sp2.before_autospacing == Some(false),
        "P2 (control) should not have beforeAutospacing"
    );

    // P0: before=480 with beforeAutospacing="1"
    let sp0 = paras[0].spacing.as_ref().expect("P0 should have spacing");
    assert_eq!(
        sp0.before_autospacing,
        Some(true),
        "P0 should have before_autospacing=true"
    );
    assert_eq!(
        sp0.before,
        Some(480),
        "P0 before raw value preserved for roundtrip (ignored per §17.3.1.33)"
    );
}

/// §17.3.1.33: afterAutospacing="1" — flag is parsed, raw value preserved.
#[test]
fn sa01_autospacing_after_flag_and_value() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "autospacing-override");
    let paras = common::all_paragraphs(&doc);

    let sp1 = paras[1].spacing.as_ref().expect("P1 should have spacing");
    assert_eq!(
        sp1.after_autospacing,
        Some(true),
        "P1 should have after_autospacing=true"
    );
    assert_eq!(
        sp1.after,
        Some(480),
        "P1 after raw value preserved for roundtrip (ignored per §17.3.1.33)"
    );
}

/// §17.3.1.33: beforeAutospacing overrides BOTH before AND beforeLines.
/// Both raw values preserved, autospacing flag signals they're ignored.
#[test]
fn sa01_autospacing_overrides_before_lines_too() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "autospacing-override");
    let paras = common::all_paragraphs(&doc);

    // P3: before=480, beforeLines=200, beforeAutospacing="1"
    let sp3 = paras[3].spacing.as_ref().expect("P3 should have spacing");
    assert_eq!(
        sp3.before_autospacing,
        Some(true),
        "P3 should have before_autospacing=true"
    );
    assert_eq!(
        sp3.before,
        Some(480),
        "P3 before raw value preserved for roundtrip"
    );
    assert_eq!(
        sp3.before_lines,
        Some(200),
        "P3 before_lines raw value preserved for roundtrip. \
         Both before AND beforeLines are ignored per §17.3.1.33 \
         when beforeAutospacing is set."
    );
}

// =========================================================================
// SA-02: contextualSpacing explicit false cannot override style's true
// =========================================================================
//
// §17.3.1.9: contextualSpacing is a boolean property that follows the
// standard style hierarchy rules. Direct formatting overrides style.
// When a paragraph has explicit <w:contextualSpacing w:val="0"/>, it
// should override the style's contextualSpacing=true.
//
// The domain model uses `Option<bool>` for contextual_spacing, correctly
// distinguishing None (absent/inherit) from Some(false) (explicitly off).

/// §17.3.1.9: Direct contextualSpacing val="0" should override style's true.
#[test]
fn sa02_contextual_spacing_explicit_false_overrides_style() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "contextual-spacing-explicit-false");
    let paras = common::all_paragraphs(&doc);
    assert!(
        paras.len() >= 3,
        "expected at least 3 paragraphs, got {}",
        paras.len()
    );

    // P1: no direct contextualSpacing — should inherit true from CtxStyle
    assert_eq!(
        paras[1].contextual_spacing,
        Some(true),
        "P1: should inherit contextual_spacing=Some(true) from CtxStyle"
    );

    // P2: direct contextualSpacing (no val) — should be Some(true)
    assert_eq!(
        paras[2].contextual_spacing,
        Some(true),
        "P2: direct contextualSpacing (no val) should be Some(true)"
    );

    // P0: explicit contextualSpacing val="0" — MUST override style's true
    assert_eq!(
        paras[0].contextual_spacing,
        Some(false),
        "P0: explicit contextualSpacing val='0' should override CtxStyle's true. \
         §17.3.1.9: direct formatting overrides style in the hierarchy."
    );
}

// =========================================================================
// SA-03: firstLine/hanging mutual exclusivity (twip level)
// =========================================================================
//
// §17.3.1.12: "The firstLine and hanging attributes are mutually
// exclusive, if both are specified, then the firstLine value is ignored."
//
// Verifies that hanging wins over firstLine when both are present,
// per the spec's mutual exclusivity rule.

/// §17.3.1.12: When both firstLine and hanging are present on the same
/// w:ind element, firstLine is IGNORED and hanging takes effect.
#[test]
fn sa03_firstline_and_hanging_both_present_hanging_wins() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "firstline-hanging-chars-exclusive");
    let paras = common::all_paragraphs(&doc);
    assert!(
        paras.len() >= 4,
        "expected at least 4 paragraphs, got {}",
        paras.len()
    );

    // P3: firstLine=360 + hanging=720 — spec says firstLine is IGNORED
    let ind3 = paras[3].indent.as_ref().expect("P3 should have indent");
    assert_eq!(
        ind3.effective_first_line_twips,
        Some(-720),
        "P3: both firstLine=360 and hanging=720 present. \
         §17.3.1.12: 'The firstLine and hanging attributes are mutually \
         exclusive, if both are specified, then the firstLine value is \
         ignored.' Expected: effective_first_line=-720 (hanging wins)."
    );
}

// =========================================================================
// SA-04: firstLineChars/hangingChars mutual exclusivity (char level)
// =========================================================================
//
// §17.3.1.12: "The firstLineChars and hangingChars attributes are
// mutually exclusive, if both are specified, then the firstLineChars
// value is ignored."
//
// Verifies that firstLineChars is ignored when hangingChars is present.

/// §17.3.1.12: When both firstLineChars and hangingChars are present,
/// firstLineChars should be ignored.
#[test]
fn sa04_firstline_chars_and_hanging_chars_both_present() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "firstline-hanging-chars-exclusive");
    let paras = common::all_paragraphs(&doc);

    // P0: firstLineChars=200 + hangingChars=100 — firstLineChars is IGNORED
    let ind0 = paras[0].indent.as_ref().expect("P0 should have indent");

    // hangingChars should be present
    assert_eq!(
        ind0.hanging_chars,
        Some(100),
        "P0 hanging_chars should be 100"
    );

    // firstLineChars should be IGNORED (None) when hangingChars is present
    assert_eq!(
        ind0.first_line_chars, None,
        "P0: firstLineChars should be None (ignored) when hangingChars is present. \
         §17.3.1.12: 'The firstLineChars and hangingChars attributes are \
         mutually exclusive, if both are specified, then the firstLineChars \
         value is ignored.'"
    );
}

/// §17.3.1.12: Control tests — firstLineChars and hangingChars work
/// correctly when used alone.
#[test]
fn sa04_firstline_chars_and_hanging_chars_individual_controls() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "firstline-hanging-chars-exclusive");
    let paras = common::all_paragraphs(&doc);

    // P1: firstLineChars=200 only — should be stored
    let ind1 = paras[1].indent.as_ref().expect("P1 should have indent");
    assert_eq!(
        ind1.first_line_chars,
        Some(200),
        "P1 first_line_chars should be 200"
    );
    assert_eq!(ind1.hanging_chars, None, "P1 hanging_chars should be None");

    // P2: hangingChars=100 only — should be stored
    let ind2 = paras[2].indent.as_ref().expect("P2 should have indent");
    assert_eq!(
        ind2.hanging_chars,
        Some(100),
        "P2 hanging_chars should be 100"
    );
    assert_eq!(
        ind2.first_line_chars, None,
        "P2 first_line_chars should be None"
    );
}

// =========================================================================
// SA-05: lineRule defaults to auto when omitted but line is present
// =========================================================================
//
// §17.3.1.33: "If this attribute [lineRule] is omitted, then it shall be
// assumed to be of a value auto if a line attribute value is present."
//
// Our parser handles this correctly in extract_spacing() (word_ir.rs ~1786).
// This test confirms the behavior.

/// §17.3.1.33: lineRule defaults to auto when line is present but lineRule omitted.
#[test]
fn sa05_line_rule_defaults_to_auto() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "line-rule-default-auto");
    let paras = common::all_paragraphs(&doc);
    assert!(
        paras.len() >= 4,
        "expected at least 4 paragraphs, got {}",
        paras.len()
    );

    // P0: line=276, no lineRule -> should default to auto
    let sp0 = paras[0].spacing.as_ref().expect("P0 should have spacing");
    assert_eq!(sp0.line, Some(276), "P0 line should be 276");
    assert_eq!(
        sp0.line_rule,
        Some(LineSpacingRule::Auto),
        "P0 lineRule should default to Auto when omitted with line present. \
         §17.3.1.33: 'If this attribute is omitted, then it shall be assumed \
         to be of a value auto if a line attribute value is present.'"
    );

    // P1: explicit auto (control)
    let sp1 = paras[1].spacing.as_ref().expect("P1 should have spacing");
    assert_eq!(sp1.line, Some(276), "P1 line should be 276");
    assert_eq!(
        sp1.line_rule,
        Some(LineSpacingRule::Auto),
        "P1 lineRule should be Auto (explicit)"
    );

    // P2: explicit exact
    let sp2 = paras[2].spacing.as_ref().expect("P2 should have spacing");
    assert_eq!(sp2.line, Some(240), "P2 line should be 240");
    assert_eq!(
        sp2.line_rule,
        Some(LineSpacingRule::Exact),
        "P2 lineRule should be Exact"
    );

    // P3: direct before=120 only, no line — per-attribute inheritance means
    // line=276 and lineRule=auto inherit from pPrDefault (docDefaults).
    let sp3 = paras[3].spacing.as_ref().expect("P3 should have spacing");
    assert_eq!(
        sp3.line,
        Some(276),
        "P3 line should inherit 276 from docDefaults (per-attribute, §17.3.1.33)"
    );
    assert_eq!(
        sp3.line_rule,
        Some(LineSpacingRule::Auto),
        "P3 lineRule should inherit auto from docDefaults (per-attribute, §17.3.1.33)"
    );
}

// =========================================================================
// SA-06: startChars/endChars supersede start/end — both preserved
// =========================================================================
//
// §17.3.1.12: "if the startChars attribute is specified, then this [start]
// value is ignored, and is superseded by this value."
// Both values should be preserved in our model for roundtrip fidelity.

/// §17.3.1.12: startChars supersedes start — both should be preserved
/// in the model for roundtrip, but consumers must use startChars.
#[test]
fn sa06_start_chars_and_start_both_preserved() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "start-chars-supersedes-start");
    let paras = common::all_paragraphs(&doc);
    assert!(
        paras.len() >= 4,
        "expected at least 4 paragraphs, got {}",
        paras.len()
    );

    // P0: start=720 + startChars=200 — both should be in model
    let ind0 = paras[0].indent.as_ref().expect("P0 should have indent");
    assert_eq!(ind0.left, Some(720), "P0 left should be 720 (from w:start)");
    assert_eq!(
        ind0.start_chars,
        Some(200),
        "P0 start_chars should be 200. §17.3.1.12: startChars supersedes start."
    );

    // P1: end=720 + endChars=100 — both should be in model
    let ind1 = paras[1].indent.as_ref().expect("P1 should have indent");
    assert_eq!(ind1.right, Some(720), "P1 right should be 720 (from w:end)");
    assert_eq!(
        ind1.end_chars,
        Some(100),
        "P1 end_chars should be 100. §17.3.1.12: endChars supersedes end."
    );

    // P2: start=720 only — no char-unit
    let ind2 = paras[2].indent.as_ref().expect("P2 should have indent");
    assert_eq!(ind2.left, Some(720), "P2 left should be 720");
    assert_eq!(ind2.start_chars, None, "P2 start_chars should be None");

    // P3: startChars=200 only — no twip value
    let ind3 = paras[3].indent.as_ref().expect("P3 should have indent");
    assert_eq!(ind3.left, None, "P3 left should be None (only startChars)");
    assert_eq!(ind3.start_chars, Some(200), "P3 start_chars should be 200");
}

// =========================================================================
// SA-07: firstLineChars supersedes firstLine — both preserved
// =========================================================================
//
// §17.3.1.12: "If the firstLine attribute is also specified, then this
// [firstLineChars] value supersedes its other value."

/// §17.3.1.12: firstLineChars supersedes firstLine, hangingChars supersedes hanging.
/// Both values should be preserved in the model for roundtrip.
#[test]
fn sa07_firstline_chars_supersedes_firstline_both_preserved() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "firstline-chars-supersedes-firstline");
    let paras = common::all_paragraphs(&doc);
    assert!(
        paras.len() >= 4,
        "expected at least 4 paragraphs, got {}",
        paras.len()
    );

    // P0: firstLine=360 + firstLineChars=200 — firstLineChars supersedes
    let ind0 = paras[0].indent.as_ref().expect("P0 should have indent");
    assert_eq!(
        ind0.effective_first_line_twips,
        Some(360),
        "P0 effective_first_line should be 360 (raw twip value preserved for roundtrip)"
    );
    assert_eq!(
        ind0.first_line_chars,
        Some(200),
        "P0 first_line_chars should be 200. §17.3.1.12: firstLineChars \
         supersedes firstLine when both present."
    );

    // P1: hanging=720 + hangingChars=100 — hangingChars supersedes
    let ind1 = paras[1].indent.as_ref().expect("P1 should have indent");
    assert_eq!(
        ind1.effective_first_line_twips,
        Some(-720),
        "P1 effective_first_line should be -720 (hanging=720)"
    );
    assert_eq!(
        ind1.hanging_chars,
        Some(100),
        "P1 hanging_chars should be 100. §17.3.1.12: hangingChars \
         supersedes hanging when both present."
    );

    // P2: firstLine=360 only
    let ind2 = paras[2].indent.as_ref().expect("P2 should have indent");
    assert_eq!(
        ind2.effective_first_line_twips,
        Some(360),
        "P2 firstLine=360"
    );
    assert_eq!(
        ind2.first_line_chars, None,
        "P2 first_line_chars should be None"
    );

    // P3: firstLineChars=200 only (no twip-level firstLine)
    let ind3 = paras[3].indent.as_ref().expect("P3 should have indent");
    assert_eq!(
        ind3.first_line_chars,
        Some(200),
        "P3 first_line_chars should be 200"
    );
    // effective_first_line_twips is None since only char-unit was specified
    assert_eq!(
        ind3.effective_first_line_twips, None,
        "P3 effective_first_line should be None (only char-unit specified)"
    );
}

// =========================================================================
// SA-08: beforeLines/afterLines presence alongside before/after
// =========================================================================
//
// §17.3.1.33: When both beforeLines and before are specified, beforeLines
// takes precedence. Both values should be preserved in the model.

/// §17.3.1.33: Both before and beforeLines preserved, both after and afterLines preserved.
/// Consumers must prefer beforeLines/afterLines when present.
#[test]
fn sa08_both_before_lines_and_before_preserved() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "both-before-lines-and-before");
    let paras = common::all_paragraphs(&doc);
    assert!(
        paras.len() >= 5,
        "expected at least 5 paragraphs, got {}",
        paras.len()
    );

    // P0: before=480 + beforeLines=100
    let sp0 = paras[0].spacing.as_ref().expect("P0 should have spacing");
    assert_eq!(sp0.before, Some(480), "P0 before should be 480");
    assert_eq!(
        sp0.before_lines,
        Some(100),
        "P0 before_lines should be 100. §17.3.1.33: beforeLines takes \
         precedence over before when both present."
    );

    // P1: after=480 + afterLines=200
    let sp1 = paras[1].spacing.as_ref().expect("P1 should have spacing");
    assert_eq!(sp1.after, Some(480), "P1 after should be 480");
    assert_eq!(sp1.after_lines, Some(200), "P1 after_lines should be 200");

    // P2: before=480 only
    let sp2 = paras[2].spacing.as_ref().expect("P2 should have spacing");
    assert_eq!(sp2.before, Some(480), "P2 before should be 480");
    assert_eq!(sp2.before_lines, None, "P2 before_lines should be None");

    // P3: beforeLines=100 only
    let sp3 = paras[3].spacing.as_ref().expect("P3 should have spacing");
    assert_eq!(sp3.before, None, "P3 before should be None");
    assert_eq!(sp3.before_lines, Some(100), "P3 before_lines should be 100");

    // P4: before=0 + beforeLines=100
    let sp4 = paras[4].spacing.as_ref().expect("P4 should have spacing");
    assert_eq!(sp4.before, Some(0), "P4 before should be 0 (explicit zero)");
    assert_eq!(sp4.before_lines, Some(100), "P4 before_lines should be 100");
}

// =========================================================================
// SA-09: pPrChange import drops char-unit indent values
// =========================================================================
//
// §17.13.5.29 + §17.3.1.12: The convert_ppr_change function in import.rs
// (line ~3094) hardcodes:
//   start_chars: None, end_chars: None, first_line_chars: None, hanging_chars: None
//
// This means char-unit indent values from previous paragraph properties
// in tracked changes are silently dropped. While the normalization step
// strips pPrChange on initial import, the code IS used during redline
// export re-import and should be correct.
//
// This is documented as a code-level bug rather than a runtime test since
// normalization prevents us from testing it through the standard import path.

// NOTE: The pPrChange conversion code (import.rs ~line 3094) explicitly
// drops char-unit indent values:
//
//   let previous_indentation = ppr_change.previous_indentation.as_ref().map(|i| Indentation {
//       left: i.left,
//       right: i.right,
//       effective_first_line_twips: i.effective_first_line_twips,
//       start_chars: None, end_chars: None, first_line_chars: None, hanging_chars: None,
//   });
//
// This is a spec violation: §17.13.5.29 says pPrChange preserves the
// complete previous pPr, including character-unit indent attributes.
//
// Additionally, the serializer (serialize.rs ~line 850) only emits
// left/right/firstLine/hanging for previous_indentation, omitting
// startChars/endChars/firstLineChars/hangingChars.
//
// And the serializer for previous_spacing (serialize.rs ~line 829)
// omits beforeLines and afterLines.
//
// These are serialization-level bugs that cannot be exercised through
// the standard import path because normalization strips pPrChange.
// They would manifest when a consumer receives a redline-exported DOCX
// and opens it in Word — the tracked change diff would be incorrect.

// SA-02: an explicit autospacing OVERRIDE ("0") survives serialization.
//
// §17.3.1.33 is tri-state: absent (inherit), "1" (auto spacing on), "0"
// (explicitly OFF — overriding an inherited "1", e.g. from NormalWeb).
// Collapsing Some(false) to absent flips the paragraph back to the
// inherited auto spacing — a Word-visible layout change on an untouched
// paragraph. Witnessed in the wild: a one-word tracked edit rebuilt a
// NormalWeb document and dropped every explicit `w:beforeAutospacing="0"`/
// `w:afterAutospacing="0"`, which the delivery verifier then correctly
// flagged as untouched-block modifications.

/// The explicit "0" override must be re-emitted by the rebuild path.
#[test]
fn sa02_explicit_autospacing_off_survives_rebuild() {
    use std::io::Write;
    use stemma::ExportOptions;
    use stemma::api::Document;
    use stemma::edit_v4::parse_transaction;

    let document_xml = concat!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>"#,
        r#"<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>"#,
        r#"<w:p><w:pPr><w:spacing w:before="0" w:beforeAutospacing="0" w:after="0" w:afterAutospacing="0"/></w:pPr>"#,
        r#"<w:r><w:t>Spaced paragraph.</w:t></w:r></w:p>"#,
        r#"<w:sectPr/></w:body></w:document>"#,
    );
    let mut bytes = Vec::new();
    {
        use zip::write::FileOptions;
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut bytes));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(br#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/><Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/></Types>"#).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(br#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(br#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"/>"#).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        zip.finish().unwrap();
    }

    let doc = Document::parse(&bytes).expect("parse");
    let block = &doc.read().blocks[0];
    let txn_json = format!(
        r#"{{ "ops": [ {{ "op": "replace", "target": "{}", "guard": "{}",
               "content": {{ "type": "paragraph",
                             "content": [ {{ "type": "text", "text": "Rewritten paragraph." }} ] }} }} ],
             "revision": {{ "author": "Spec Test" }} }}"#,
        block.id, block.guard
    );
    let txn = parse_transaction(&txn_json)
        .unwrap()
        .into_edit_transaction()
        .unwrap();
    let edited = doc.apply(&txn).expect("tracked edit applies");
    let out = edited
        .serialize(&ExportOptions::default())
        .expect("serialize");

    let mut zip = zip::ZipArchive::new(std::io::Cursor::new(out)).expect("zip");
    let mut xml = String::new();
    std::io::Read::read_to_string(&mut zip.by_name("word/document.xml").unwrap(), &mut xml)
        .unwrap();
    assert!(
        xml.contains(r#"w:beforeAutospacing="0""#),
        "the explicit beforeAutospacing override must survive: {xml}"
    );
    assert!(
        xml.contains(r#"w:afterAutospacing="0""#),
        "the explicit afterAutospacing override must survive: {xml}"
    );
}
